local LWonderBase = LXImport("..Base.LWonderBase")
---@class LWonderIconCtrl:LWonderBase
local LWonderIconCtrl = LxClass("LWonderIconCtrl",LWonderBase)
local typeSpriteRenderer = typeof(UnityEngine.SpriteRenderer)

function LWonderIconCtrl:LWonderIconCtrl()
    self._objList = {}
end

function LWonderIconCtrl:InitCtrl(root,template)
    self._root = root
    self._template = template
end

function LWonderIconCtrl:MakeObject(objData)
    local key = objData.key
    local objectData = self._objList[key]
    local endFunc = objData.endFunc
    if objectData then
        objectData.objData = objData
    else
        local itemNew = LxResUtil.NewObject(self._template)
        itemNew.name = tostring(key)
        objectData = {obj = itemNew,objData = objData}
        self._objList[key] = objectData
    end

    self:OnObjLoaded(objectData.obj,objData)
    if endFunc then
        endFunc(objectData.obj)
    end
end

function LWonderIconCtrl:OnObjLoaded(item,objData)
    local trans = item.transform
    trans:SetParent(self._root,false)
    self:SetSprite(trans,trans,objData.resName,nil)
    local spriteRender = trans:GetComponent(typeSpriteRenderer)
    spriteRender.sortingOrder = objData.sorting
    trans.localPosition = objData.pos or Vector3.zero
    trans.localScale = Vector3.New(objData.scale,objData.scale,objData.scale)
    trans.name = objData.resName
end

function LWonderIconCtrl:Clear()
    local list = {}
    for k,v in pairs(self._objList) do
        table.insert(list,k)
    end

    for k,v in ipairs(list) do
        self:DestroyByKey(v)
    end

    self._objList = {}
end

function LWonderIconCtrl:DestroyByKey(key)
    local objectdata = self._objList[key]
    self._objList[key] = nil
    if not objectdata then
        return
    end
    local obj = objectdata.obj
    LxResUtil.DestroyObject(obj)

    --self:ReleaseDepend(objectdata.iconPath)
end




return LWonderIconCtrl